class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        sort(time.begin(), time.end());
        vector<int> people;
        for (int i = n - 1; i >= 0; --i) people.push_back(time[i]);
        vector<vector<double>> dp(1 << n, vector<double>(m, -1));
        function<double(int, int)> dfs = [&](int state, int stage) {
            if (state == 0) return 0.0;
            if (dp[state][stage] != -1) return dp[state][stage];
            double res = 1e9;
            int cnt = 0;
            vector<int> group;
            for (int i = 0; i < n; ++i) {
                if ((state >> i) & 1) {
                    group.push_back(people[i]);
                    cnt++;
                    if (cnt == k) break;
                }
            }
            if (group.empty()) return 1e9;
            double crossTime = *max_element(group.begin(), group.end()) * mul[stage];
            int nextStage = (stage + (int)crossTime % m) % m;
            int newState = state;
            for (int num : group) newState ^= (1 << (n - 1 - (lower_bound(people.begin(), people.end(), num) - people.begin())));
            double minReturnTime = 1e9;
            for (int i = 0; i < n; ++i) {
                if ((newState >> i) & 1) {
                    minReturnTime = min(minReturnTime, people[i] * mul[nextStage]);
                }
            }
            if (minReturnTime == 1e9) {
                res = crossTime + dfs(newState, nextStage);
            } else {
                int returnStage = (nextStage + (int)minReturnTime % m) % m;
                res = crossTime + minReturnTime + dfs(newState ^ (1 << (n - 1 - (lower_bound(people.begin(), people.end(), people[lower_bound(people.begin(), people.end(), minReturnTime / mul[nextStage]) - people.begin()]) - people.begin()))), returnStage);
            }
            return dp[state][stage] = res;
        };
        double ans = dfs((1 << n) - 1, 0);
        return ans >= 1e9 ? -1 : ans;
    }
};
